VALUES ('00000000-0000-0000-0000-000000000001', '11f5c353-c327-4dd0-b90b-f753d56eb600', $$Gagaku$$, $$gagaku$$, '36ea1a6e-5615-48dc-9c2f-c8cc87d2dfd4', NULL, NULL, $$Música clássica da corte imperial japonesa. Uma das formas de música orquestral mais antigas do mundo ainda praticadas. Solene e ritualística.$$, $${"ritmo": "Lento e majestoso", "escalas": "Modi japoneses", "estrutura": "Ensemble orquestral", "instrumentos": ["hichiriki", "ryuteki", "biwa", "koto"]}$$, '[]', '[]', '[]', NULL, NULL, NULL, true, '2025-12-14 20:49:33.510717+00'::timestamptz)
