INSERT INTO core.history_genres (tenant_id, id, name, slug, origin_period_id, origin_decade, origin_country, description, musical_characteristics, related_genres, main_composers, representative_works, cultural_influences, image_url, theme_color, is_active, created_at)
VALUES ('00000000-0000-0000-0000-000000000001', '21d4204e-4785-435a-8b06-19cb7761373b', $$Reggae$$, $$reggae$$, NULL, $$1968$$, $$Jamaica$$, $$Voz da Jamaica para o mundo. Ritmo sincopado, mensagem de paz, amor e resistência. Movimento Rastafári e consciência social.$$, $${"obras": ["No Woman No Cry - Bob Marley", "Redemption Song - Marley", "The Harder They Come - Jimmy Cliff"], "temas": ["Rastafári", "Justiça social", "Paz", "Amor", "Resistência", "Repatriação", "Crítica ao sistema (Babylon)"], "estilos": ["Roots Reggae", "Dub", "Dancehall", "Lovers Rock", "Reggae Fusion"], "artistas": ["Bob Marley", "Peter Tosh", "Burning Spear", "Jimmy Cliff", "Toots and the Maytals", "Lee \"Scratch\" Perry", "King Tubby"], "estrutura": ["Ênfase no contratempo (offbeat)", "Baixo proeminente e melódico", "Skank característico (guitarra)", "Tempo médio/lento", "One drop (bateria)"]}$$, '[]', '[]', '[]', $$Jamaica, final anos 60. Evolução do ska/rocksteady. Movimento Rastafári. Bob Marley levou ao mundo. UNESCO: Patrimônio Imaterial.$$, NULL, $$#16a34a$$, true, '2025-10-27 18:41:40.135539+00'::timestamptz)
ON CONFLICT (id) DO NOTHING;

INSERT INTO core.history_genres (tenant_id, id, name, slug, origin_period_id, origin_decade, origin_country, description, musical_characteristics, related_genres, main_composers, representative_works, cultural_influences, image_url, theme_color, is_active, created_at)
VALUES ('00000000-0000-0000-0000-000000000001', '23588b5b-865c-4f2a-9bdc-31aaed701a57', $$Bossa Nova$$, $$bossa-nova$$, NULL, $$1958$$, $$Brasil$$, $$Sofisticação brasileira que conquistou o mundo. Fusão de samba com jazz cool. "Batida diferente" que revolucionou a MPB.$$, $${"obras": ["Garota de Ipanema", "Chega de Saudade", "Desafinado", "Corcovado", "Águas de Março", "Wave"], "estilos": ["Bossa Nova Clássica", "Samba-jazz", "MPB (evolução)"], "artistas": ["Tom Jobim", "João Gilberto", "Vinicius de Moraes", "Stan Getz", "Elis Regina", "Nara Leão", "Astrud Gilberto", "Baden Powell"], "estrutura": ["Batida sincopada no violão", "Harmonia sofisticada (jazz)", "Melodia suave e intimista", "Ritmo de samba \"quebrado\"", "Influência do cool jazz"], "instrumentos": ["Violão (batida característica)", "Piano", "Baixo", "Bateria leve", "Flauta", "Voz suave"]}$$, '[]', '[]', '[]', $$Rio de Janeiro, final anos 50. Zona Sul carioca, intelectuais, classe média. Fusão samba + jazz. Sucesso internacional (Getz/Gilberto 1964).$$, NULL, $$#06b6d4$$, true, '2025-10-27 18:41:40.135539+00'::timestamptz)
ON CONFLICT (id) DO NOTHING;

INSERT INTO core.history_genres (tenant_id, id, name, slug, origin_period_id, origin_decade, origin_country, description, musical_characteristics, related_genres, main_composers, representative_works, cultural_influences, image_url, theme_color, is_active, created_at)
VALUES ('00000000-0000-0000-0000-000000000001', '33fdd046-f688-4b0d-9a8c-9485e86b3348', $$MPB$$, $$mpb$$, NULL, $$1965$$, $$Brasil$$, $$Termo guarda-chuva para música brasileira de qualidade pós-Bossa Nova. Fusão de tradições brasileiras com influências internacionais.$$, $${"obras": ["Construção - Chico", "Águas de Março - Tom", "Alegria Alegria - Caetano", "Cálice - Chico/Gil"], "artistas": ["Chico Buarque", "Caetano Veloso", "Gilberto Gil", "Elis Regina", "Milton Nascimento", "Gal Costa", "Maria Bethânia", "Djavan"], "estrutura": ["Diversidade estilística", "Letra poética/literária", "Harmonia sofisticada", "Fusão de gêneros", "Experimentação"], "movimentos": ["Tropicália (1968)", "Clube da Esquina", "Vanguarda Paulista", "Música de Resistência (Ditadura)"], "influencias": ["Bossa Nova", "Samba", "Rock", "Jazz", "Música Nordestina", "Música Erudita"]}$$, '[]', '[]', '[]', $$Anos 60-70. Resposta à ditadura militar, Festivais da Canção TV Record. Sofisticação + engajamento político. Identidade brasileira moderna.$$, NULL, $$#8b5cf6$$, true, '2025-10-27 18:41:40.135539+00'::timestamptz)
ON CONFLICT (id) DO NOTHING;

INSERT INTO core.history_genres (tenant_id, id, name, slug, origin_period_id, origin_decade, origin_country, description, musical_characteristics, related_genres, main_composers, representative_works, cultural_influences, image_url, theme_color, is_active, created_at)
VALUES ('00000000-0000-0000-0000-000000000001', '395cfb8c-2660-4827-8467-e4e8acdd625e', $$Tropicália$$, $$tropicalia$$, '480e5257-9aca-48e8-971f-f19794fc0dcf', NULL, NULL, $$Movimento de vanguarda que revolucionou a MPB. Mistura antropofágica de rock, samba, baião, música regional e experimentação. Letras poéticas e crítica social.$$, $${"estrutura": "Experimental", "instrumentos": ["guitarra elétrica", "berimbau", "instrumentos regionais", "eletrônica"], "caracteristicas": "Antropofagia cultural, fusão radical, engajamento político"}$$, '[]', '[]', '[]', NULL, NULL, NULL, true, '2025-12-14 20:49:33.510717+00'::timestamptz)
ON CONFLICT (id) DO NOTHING;

