VALUES ('00000000-0000-0000-0000-000000000001', '3a16c10a-e2e3-4b98-89f3-37b7930928ce', $$Balada$$, $$balada$$, 'e8ce8fcc-5d20-4557-be06-c908b975e141', NULL, NULL, $$Forma musical instrumental de caráter narrativo e dramático, muitas vezes inspirada em poesia ou lendas.$$, $${"forma": "Livre", "mestre": "Chopin (para piano)", "carater": "Narrativo, dramático", "inspiracao": "Poesia, lendas"}$$, '[]', '[]', '[]', NULL, NULL, $$#a855f7$$, true, '2025-10-26 03:54:07.846053+00'::timestamptz)
