INSERT INTO core.history_genres (tenant_id, id, name, slug, origin_period_id, origin_decade, origin_country, description, musical_characteristics, related_genres, main_composers, representative_works, cultural_influences, image_url, theme_color, is_active, created_at)
VALUES ('00000000-0000-0000-0000-000000000001', '3f255cc4-dc35-4d6b-8507-07fb5d8c2da7', $$Hip-Hop$$, $$hip-hop$$, NULL, $$1973$$, $$Estados Unidos$$, $$Cultura urbana completa: rap, DJing, breakdance, graffiti. Voz das periferias, poesia urbana, denúncia social e celebração de identidade.$$, $${"obras": ["The Message - Grandmaster Flash", "Fight the Power - Public Enemy", "Alright - Kendrick Lamar"], "temas": ["Realidade das periferias", "Racismo e injustiça", "Superação", "Ostentação", "Política", "Identidade negra"], "estilos": ["Old School", "Golden Age", "Gangsta Rap", "Conscious Rap", "Trap", "Boom Bap", "Alternative Hip-Hop"], "artistas": ["Grandmaster Flash", "Run-DMC", "Public Enemy", "Tupac", "Notorious B.I.G.", "Nas", "Kendrick Lamar", "J. Cole"], "elementos": ["MCing/Rap", "DJing", "Breakdance", "Graffiti", "Beatboxing", "Knowledge (consciência)"], "estrutura": ["Rap (ritmo e poesia)", "Beat (base instrumental)", "Sampling (uso de trechos de outras músicas)", "Scratch (DJ)", "Flow (cadência do rap)"]}$$, '[]', '[]', '[]', $$Bronx, Nova York, anos 70. DJ Kool Herc, Afrika Bambaataa. Cultura de resistência afro-latina. Globalizou-se: maior gênero mundial hoje.$$, NULL, $$#7c3aed$$, true, '2025-10-27 18:41:40.135539+00'::timestamptz)
ON CONFLICT (id) DO NOTHING;

INSERT INTO core.history_genres (tenant_id, id, name, slug, origin_period_id, origin_decade, origin_country, description, musical_characteristics, related_genres, main_composers, representative_works, cultural_influences, image_url, theme_color, is_active, created_at)
VALUES ('00000000-0000-0000-0000-000000000001', '45c82306-d206-465c-9ed1-bf3a4ea8a5be', $$Afrobeat$$, $$afrobeat$$, NULL, $$1970$$, $$Nigéria$$, $$Fusão explosiva de funk, jazz, highlife e ritmos yorubá. Criado por Fela Kuti na Nigéria. Música como arma política e celebração africana.$$, $${"obras": ["Zombie - Fela Kuti", "Water No Get Enemy - Fela", "Expensive Shit - Fela"], "temas": ["Crítica ao colonialismo", "Corrupção governamental", "Pan-africanismo", "Orgulho negro", "Resistência"], "artistas": ["Fela Kuti", "Tony Allen", "Antibalas", "Seun Kuti", "Femi Kuti", "Ebo Taylor", "Orchestra Baobab"], "estrutura": ["Groove hipnótico e repetitivo", "Seção de metais poderosa (jazz)", "Polirritmia complexa (percussão africana)", "Músicas longas (10-20 min)", "Call-response"], "influencias": ["Highlife (Gana/Nigéria)", "Funk (James Brown)", "Jazz", "Música Yorubá", "Política Pan-Africana"], "instrumentos": ["Saxofones", "Trompetes", "Guitarra", "Baixo", "Bateria", "Congas", "Shekere", "Teclados"]}$$, '[]', '[]', '[]', $$Lagos, Nigéria, anos 70. Fela Kuti cria fusão única. Ativismo político contra ditadura militar. Shrine (clube). Influência global moderna.$$, NULL, $$#ea580c$$, true, '2025-10-27 18:41:40.135539+00'::timestamptz)
ON CONFLICT (id) DO NOTHING;

INSERT INTO core.history_genres (tenant_id, id, name, slug, origin_period_id, origin_decade, origin_country, description, musical_characteristics, related_genres, main_composers, representative_works, cultural_influences, image_url, theme_color, is_active, created_at)
VALUES ('00000000-0000-0000-0000-000000000001', '47442ac7-2734-436d-a5a8-9d386928c18e', $$Música Eletrônica$$, $$eletronica$$, NULL, $$1970$$, $$Alemanha/EUA$$, $$Revolução tecnológica na música. De experimentos acadêmicos a cultura de club global. Sintetizadores, samplers e computadores como instrumentos.$$, $${"cenas": ["Chicago House (anos 80)", "Detroit Techno", "UK Rave", "Ibiza", "Berlin Techno", "EDM (festivais)"], "obras": ["Blue Monday - New Order", "Around the World - Daft Punk", "Windowlicker - Aphex Twin"], "estilos": ["House", "Techno", "Trance", "Drum and Bass", "Dubstep", "EDM", "Ambient", "IDM", "Breakbeat"], "estrutura": ["Produção totalmente eletrônica", "Batida repetitiva (4/4)", "Build-up e drop", "Síntese sonora", "Loops e camadas"], "pioneiros": ["Kraftwerk", "Jean-Michel Jarre", "Giorgio Moroder", "Detroit Techno: Derrick May/Juan Atkins", "Daft Punk", "Aphex Twin"], "tecnologia": ["Sintetizadores", "Drum machines (TR-808, 909)", "Samplers", "DAWs (Ableton, FL Studio)", "Controllers"]}$$, '[]', '[]', '[]', $$Anos 70-80. Kraftwerk (Alemanha), Chicago House, Detroit Techno. Cultura club/rave. Democratizou produção musical (laptops).$$, NULL, $$#ec4899$$, true, '2025-10-27 18:41:40.135539+00'::timestamptz)
ON CONFLICT (id) DO NOTHING;

