VALUES ('00000000-0000-0000-0000-000000000001', '4cc882da-037f-4306-8b42-971bf32c6c2f', $$Prelúdio$$, $$preludio$$, 'd8c30e03-788e-4a90-970c-7585963b3949', NULL, NULL, $$Peça instrumental breve que originalmente servia como introdução a outra obra, mas que se desenvolveu como forma independente.$$, $${"forma": "Livre", "carater": "Improvisatório", "duracao": "2-5 minutos", "natureza": "Introdutória ou independente"}$$, '[]', '[]', '[]', NULL, NULL, $$#10b981$$, true, '2025-10-26 03:54:07.846053+00'::timestamptz)
