VALUES ('00000000-0000-0000-0000-000000000001', '5c4d2954-3812-448a-8ca4-169f292cd37b', $$J-Pop$$, $$j-pop$$, 'bf731274-4647-4e61-aa72-2ac8a0b3944c', NULL, NULL, $$Pop japonês mainstream. Produção sofisticada, melodias cativantes, influências de rock, eletrônica e R&B. Fenômeno cultural global.$$, $${"producao": "Alta qualidade", "estrutura": "Pop comercial", "instrumentos": ["sintetizadores", "guitarra", "bateria", "programação"], "caracteristicas": "Melodias complexas, mudanças de tonalidade"}$$, '[]', '[]', '[]', NULL, NULL, NULL, true, '2025-12-14 20:49:33.510717+00'::timestamptz)
