VALUES ('00000000-0000-0000-0000-000000000001', '6b8ae50f-c464-4f1f-93a7-5604ad77382d', $$Cantata$$, $$cantata$$, NULL, $$1650$$, $$Alemanha/Itália$$, $$Obra vocal média para solistas, coro e instrumentos. Sacra ou profana.$$, $${"obras": ["Cantata BWV 147 - Bach", "Cantata do Café - Bach", "Cantatas Sacras - Bach"], "estrutura": ["Vocal + instrumental", "Recitativos/árias/coros", "Mais curta que ópera", "Sacra ou profana", "Tradição luterana"], "compositores": ["Bach", "Telemann", "Scarlatti", "Buxtehude"]}$$, '[]', '[]', '[]', $$Início Barroco. Bach: 200+ cantatas sacras para liturgia luterana.$$, NULL, $$#a855f7$$, true, '2025-10-27 18:42:59.423794+00'::timestamptz)
