INSERT INTO core.history_genres (tenant_id, id, name, slug, origin_period_id, origin_decade, origin_country, description, musical_characteristics, related_genres, main_composers, representative_works, cultural_influences, image_url, theme_color, is_active, created_at)
VALUES ('00000000-0000-0000-0000-000000000001', '7b099be1-9e04-4f36-8295-777fd9951d0d', $$Pop$$, $$pop$$, NULL, $$1950$$, $$Estados Unidos/Reino Unido$$, $$Música popular acessível e cativante. Melodias memoráveis, produção polida, apelo de massa. Reflete e molda cultura contemporânea.$$, $${"eras": ["Pop dos anos 50-60 (Elvis, Beatles)", "Disco (70s)", "Synth-pop (80s)", "Teen pop (90s-2000s)", "Pop contemporâneo"], "obras": ["Thriller - Michael Jackson", "Like a Prayer - Madonna", "I Wanna Dance with Somebody - Whitney"], "temas": ["Amor e relacionamentos", "Empoderamento", "Festa e celebração", "Superação", "Identidade"], "artistas": ["Michael Jackson", "Madonna", "Prince", "Whitney Houston", "Beyoncé", "Taylor Swift", "Ariana Grande", "The Weeknd"], "estrutura": ["Verso-refrão-verso-refrão-ponte-refrão", "Melodia cativante (hook)", "Duração 3-4 minutos", "Produção refinada", "Foco no refrão"], "caracteristicas": ["Apelo universal", "Produção de alta qualidade", "Videoclipes icônicos", "Performances espetaculares", "Fenômenos virais"]}$$, '[]', '[]', '[]', $$Anos 50-60 com rock and roll. Indústria fonográfica massiva. MTV (1981) revolucionou. Globalização via streaming. Maior alcance comercial.$$, NULL, $$#f472b6$$, true, '2025-10-27 18:41:40.135539+00'::timestamptz)
ON CONFLICT (id) DO NOTHING;

