VALUES ('00000000-0000-0000-0000-000000000001', 'b6f9157c-c5e8-4bba-be8d-d6030197b1dc', $$Sinfonia$$, $$sinfonia$$, 'f8ed8ab3-ef44-47e5-8a3f-80b4dd60f89a', NULL, NULL, $$Composição orquestral em múltiplos movimentos, geralmente quatro, que representa uma das formas mais complexas e prestigiadas da música clássica.$$, $${"duracoes": "30-60 minutos", "estrutura": "4 movimentos típicos", "instrumentacao": "Orquestra completa", "forma_primeiro_movimento": "Forma sonata"}$$, '[]', '[]', '[]', NULL, NULL, $$#3b82f6$$, true, '2025-10-26 03:54:07.846053+00'::timestamptz)
