INSERT INTO core.history_genres (tenant_id, id, name, slug, origin_period_id, origin_decade, origin_country, description, musical_characteristics, related_genres, main_composers, representative_works, cultural_influences, image_url, theme_color, is_active, created_at)
VALUES ('00000000-0000-0000-0000-000000000001', 'bb2b39dd-8833-44b2-9483-39820c16be28', $$Concerto$$, $$concerto$$, 'd8c30e03-788e-4a90-970c-7585963b3949', NULL, NULL, $$Obra musical para um ou mais instrumentos solistas acompanhados por orquestra, destacando o virtuosismo do solista em diálogo com a orquestra.$$, $${"forma": "Diálogo solista-orquestra", "cadenza": "Seção improvisatória do solista", "estrutura": "3 movimentos (rápido-lento-rápido)", "elemento_principal": "Virtuosismo do solista"}$$, '[]', '[]', '[]', NULL, NULL, $$#8b5cf6$$, true, '2025-10-26 03:54:07.846053+00'::timestamptz)
ON CONFLICT (id) DO NOTHING;

INSERT INTO core.history_genres (tenant_id, id, name, slug, origin_period_id, origin_decade, origin_country, description, musical_characteristics, related_genres, main_composers, representative_works, cultural_influences, image_url, theme_color, is_active, created_at)
VALUES ('00000000-0000-0000-0000-000000000001', 'be3bbc53-97b4-4e8c-86d1-2848cb5ea697', $$Ópera$$, $$opera$$, 'd8c30e03-788e-4a90-970c-7585963b3949', NULL, NULL, $$Forma dramática de teatro musical onde o texto (libreto) é cantado com acompanhamento orquestral, combinando música, drama, poesia e artes visuais.$$, $${"origem": "Florença, 1600", "partes": "Árias, recitativos, coros", "duracao": "2-5 horas", "elementos": "Canto, orquestra, teatro, cenografia"}$$, '[]', '[]', '[]', NULL, NULL, $$#ef4444$$, true, '2025-10-26 03:54:07.846053+00'::timestamptz)
ON CONFLICT (id) DO NOTHING;

INSERT INTO core.history_genres (tenant_id, id, name, slug, origin_period_id, origin_decade, origin_country, description, musical_characteristics, related_genres, main_composers, representative_works, cultural_influences, image_url, theme_color, is_active, created_at)
VALUES ('00000000-0000-0000-0000-000000000001', 'c38a0d21-401d-4837-9db4-2f24860bf147', $$Sonata$$, $$sonata$$, 'f8ed8ab3-ef44-47e5-8a3f-80b4dd60f89a', NULL, NULL, $$Composição instrumental, geralmente em 3 ou 4 movimentos, escrita para piano solo ou um instrumento melódico com acompanhamento de piano.$$, $${"estrutura": "3-4 movimentos", "intimidade": "Performance de câmara", "forma_sonata": "Primeiro movimento em forma sonata", "instrumentacao": "1-2 instrumentos"}$$, '[]', '[]', '[]', NULL, NULL, $$#ec4899$$, true, '2025-10-26 03:54:07.846053+00'::timestamptz)
ON CONFLICT (id) DO NOTHING;

INSERT INTO core.history_genres (tenant_id, id, name, slug, origin_period_id, origin_decade, origin_country, description, musical_characteristics, related_genres, main_composers, representative_works, cultural_influences, image_url, theme_color, is_active, created_at)
VALUES ('00000000-0000-0000-0000-000000000001', 'c3e71e46-22f6-4ece-904e-61fca9db5521', $$Rock$$, $$rock$$, NULL, $$1950$$, $$Estados Unidos/Reino Unido$$, $$Revolução cultural dos anos 50. Fusão de blues, country e R&B. Símbolo de rebeldia juvenil, liberdade e transformação social.$$, $${"obras": ["Stairway to Heaven - Led Zeppelin", "Bohemian Rhapsody - Queen", "Smells Like Teen Spirit - Nirvana"], "estilos": ["Rock and Roll", "Hard Rock", "Progressive Rock", "Punk Rock", "Heavy Metal", "Alternative Rock", "Indie Rock", "Grunge"], "artistas": ["Elvis Presley", "The Beatles", "Led Zeppelin", "Pink Floyd", "Queen", "Jimi Hendrix", "Nirvana", "Radiohead"], "estrutura": ["Backbeat forte (2 e 4)", "Guitarra elétrica como protagonista", "Forma: verso-refrão", "Energia e volume altos", "Distorção e efeitos"], "instrumentos": ["Guitarra elétrica", "Baixo elétrico", "Bateria", "Teclados", "Voz"]}$$, '[]', '[]', '[]', $$Anos 50 EUA/Reino Unido. Fusão de blues, country, R&B. Contracultura, rebeldia juvenil. Transformou indústria musical e cultura global.$$, NULL, $$#dc2626$$, true, '2025-10-27 18:41:40.135539+00'::timestamptz)
ON CONFLICT (id) DO NOTHING;

INSERT INTO core.history_genres (tenant_id, id, name, slug, origin_period_id, origin_decade, origin_country, description, musical_characteristics, related_genres, main_composers, representative_works, cultural_influences, image_url, theme_color, is_active, created_at)
VALUES ('00000000-0000-0000-0000-000000000001', 'd02dafe6-4b7e-46f5-b07b-dc753433fba9', $$Blues$$, $$blues$$, NULL, $$1890$$, $$Estados Unidos$$, $$Raiz da música popular moderna. Nasceu das work songs e spirituals afro-americanos. Expressão profunda de luta, dor, alegria e resistência.$$, $${"obras": ["Cross Road Blues - Robert Johnson", "The Thrill Is Gone - B.B. King", "Hoochie Coochie Man - Muddy Waters"], "estilos": ["Delta Blues", "Chicago Blues", "Texas Blues", "Blues Rock", "Jump Blues", "British Blues"], "artistas": ["Robert Johnson", "Muddy Waters", "B.B. King", "Howlin Wolf", "John Lee Hooker", "Bessie Smith", "Etta James", "Buddy Guy"], "estrutura": ["Forma de 12 compassos (I-IV-V)", "Blue notes (3ª e 7ª bemol)", "Call and response entre voz e instrumento", "Letra em AAB (repetição + resolução)", "Expressão emocional intensa"], "instrumentos": ["Guitarra (slide/bottleneck)", "Gaita (harmônica)", "Piano", "Baixo", "Bateria", "Voz"]}$$, '[]', '[]', '[]', $$Sul dos EUA (Delta do Mississippi), final séc. XIX. Raiz africana + experiência da escravidão/segregação. Influenciou rock, R&B, soul, jazz.$$, NULL, $$#1e40af$$, true, '2025-10-27 18:41:40.135539+00'::timestamptz)
ON CONFLICT (id) DO NOTHING;

INSERT INTO core.history_genres (tenant_id, id, name, slug, origin_period_id, origin_decade, origin_country, description, musical_characteristics, related_genres, main_composers, representative_works, cultural_influences, image_url, theme_color, is_active, created_at)
VALUES ('00000000-0000-0000-0000-000000000001', 'da1b0aa5-08c7-4503-bfe1-7c2dd0de0582', $$Forró$$, $$forro$$, NULL, $$1940$$, $$Brasil$$, $$Gênero nordestino que celebra a cultura sertaneja. Bailes populares, sanfona vibrante, ritmo contagiante e alegria coletiva.$$, $${"obras": ["Asa Branca - Luiz Gonzaga", "Xote das Meninas - Gonzaga", "Pagode Russo - Gonzaga", "Feira de Mangaio"], "estilos": ["Forró Pé-de-Serra (tradicional)", "Forró Universitário", "Forró Eletrônico", "Xote", "Baião", "Arrasta-pé"], "artistas": ["Luiz Gonzaga (Rei do Baião)", "Jackson do Pandeiro", "Dominguinhos", "Elba Ramalho", "Alceu Valença", "Sivuca", "Trio Nordestino"], "estrutura": ["Compasso 2/4", "Triângulo marcando tempo", "Sanfona como melodia principal", "Zabumba na base rítmica", "Dança a dois característica"], "instrumentos": ["Sanfona (acordeão)", "Zabumba", "Triângulo", "Violão", "Baixo"]}$$, '[]', '[]', '[]', $$Nordeste brasileiro, anos 40-50. Cultura sertaneja, festas juninas, bailes populares. Luiz Gonzaga popularizou nacionalmente. Identidade nordestina.$$, NULL, $$#f59e0b$$, true, '2025-10-27 18:41:40.135539+00'::timestamptz)
ON CONFLICT (id) DO NOTHING;

INSERT INTO core.history_genres (tenant_id, id, name, slug, origin_period_id, origin_decade, origin_country, description, musical_characteristics, related_genres, main_composers, representative_works, cultural_influences, image_url, theme_color, is_active, created_at)
VALUES ('00000000-0000-0000-0000-000000000001', 'de264c2b-399a-4901-a7bb-b62408b7a512', $$Jazz$$, $$jazz$$, NULL, $$1890$$, $$Estados Unidos$$, $$Gênero nascido da fusão de tradições africanas, blues e música europeia. Caracterizado por improvisação, síncope e expressão individual dentro de estruturas coletivas.$$, $${"obras": ["Take Five - Dave Brubeck", "So What - Miles Davis", "A Love Supreme - Coltrane"], "estilos": ["Dixieland", "Swing", "Bebop", "Cool Jazz", "Hard Bop", "Free Jazz", "Fusion", "Contemporary Jazz"], "artistas": ["Louis Armstrong", "Duke Ellington", "Charlie Parker", "Miles Davis", "John Coltrane", "Ella Fitzgerald", "Billie Holiday", "Herbie Hancock"], "estrutura": ["Improvisação como elemento central", "Síncope e swing", "Call and response", "Harmonia sofisticada (7ªs, 9ªs, alterações)", "Seções: tema-improvisação-tema"], "instrumentos": ["Trompete", "Saxofone", "Piano", "Contrabaixo", "Bateria", "Trombone", "Clarinete"]}$$, '[]', '[]', '[]', $$Nova Orleans, início séc. XX. Fusão de tradições africanas (ritmo, call-response), blues rural e harmonia europeia. Expressão da experiência afro-americana.$$, NULL, $$#d97706$$, true, '2025-10-27 18:41:40.135539+00'::timestamptz)
ON CONFLICT (id) DO NOTHING;

INSERT INTO core.history_genres (tenant_id, id, name, slug, origin_period_id, origin_decade, origin_country, description, musical_characteristics, related_genres, main_composers, representative_works, cultural_influences, image_url, theme_color, is_active, created_at)
VALUES ('00000000-0000-0000-0000-000000000001', 'e1db826e-01a8-4150-9fb6-54054e7ff2e5', $$Noturno$$, $$noturno$$, 'e8ce8fcc-5d20-4557-be06-c908b975e141', NULL, NULL, $$Peça instrumental, geralmente para piano, de caráter lírico e contemplativo, evocando a atmosfera noturna.$$, $${"carater": "Lírico, contemplativo, noturno", "estrutura": "Forma livre", "instrumento": "Principalmente piano", "popularizador": "Chopin"}$$, '[]', '[]', '[]', NULL, NULL, $$#8b5cf6$$, true, '2025-10-26 03:54:07.846053+00'::timestamptz)
ON CONFLICT (id) DO NOTHING;

INSERT INTO core.history_genres (tenant_id, id, name, slug, origin_period_id, origin_decade, origin_country, description, musical_characteristics, related_genres, main_composers, representative_works, cultural_influences, image_url, theme_color, is_active, created_at)
VALUES ('00000000-0000-0000-0000-000000000001', 'ed28810b-fc8d-40c3-8530-bf6622a2c138', $$Fuga$$, $$fuga$$, 'd8c30e03-788e-4a90-970c-7585963b3949', NULL, NULL, $$Técnica composicional contrapontística rigorosa onde um tema (sujeito) é desenvolvido por imitação em diferentes vozes.$$, $${"mestre": "J.S. Bach", "tecnica": "Contraponto imitativo", "estrutura": "Exposição + Desenvolvimento", "complexidade": "Alta"}$$, '[]', '[]', '[]', NULL, NULL, $$#6366f1$$, true, '2025-10-26 03:54:07.846053+00'::timestamptz)
ON CONFLICT (id) DO NOTHING;

INSERT INTO core.history_genres (tenant_id, id, name, slug, origin_period_id, origin_decade, origin_country, description, musical_characteristics, related_genres, main_composers, representative_works, cultural_influences, image_url, theme_color, is_active, created_at)
VALUES ('00000000-0000-0000-0000-000000000001', 'ee294591-d3bd-4408-98d1-68eeb60b529d', $$Música de Câmara$$, $$musica-camara$$, NULL, $$1750$$, $$Áustria$$, $$Música para pequenos grupos instrumentais, com diálogo equilibrado entre instrumentos.$$, $${"obras": ["Quarteto Op. 76 - Haydn", "Quinteto Clarineta - Mozart", "Trio Piano Op. 97 - Beethoven"], "estrutura": ["2 a 9 músicos", "Um músico por parte", "Conversação musical", "Quarteto/trio/quinteto"], "compositores": ["Haydn", "Mozart", "Beethoven", "Schubert", "Brahms"]}$$, '[]', '[]', '[]', $$Executada em salões de palácios. Quarteto de cordas = forma suprema (Haydn, Mozart, Beethoven).$$, NULL, $$#10b981$$, true, '2025-10-27 18:42:59.423794+00'::timestamptz)
ON CONFLICT (id) DO NOTHING;

INSERT INTO core.history_genres (tenant_id, id, name, slug, origin_period_id, origin_decade, origin_country, description, musical_characteristics, related_genres, main_composers, representative_works, cultural_influences, image_url, theme_color, is_active, created_at)
VALUES ('00000000-0000-0000-0000-000000000001', 'f1c3abb7-95b4-4400-a9bb-4797888b11a6', $$Quarteto de Cordas$$, $$quarteto-cordas$$, 'f8ed8ab3-ef44-47e5-8a3f-80b4dd60f89a', NULL, NULL, $$Formação de música de câmara com quatro instrumentos de cordas (2 violinos, viola e violoncelo) e também o gênero de obras escritas para essa formação.$$, $${"textura": "4 vozes independentes", "formacao": "2 violinos + viola + violoncelo", "natureza": "Música de câmara", "intimidade": "Performance sem regente"}$$, '[]', '[]', '[]', NULL, NULL, $$#f59e0b$$, true, '2025-10-26 03:54:07.846053+00'::timestamptz)
ON CONFLICT (id) DO NOTHING;

INSERT INTO core.history_genres (tenant_id, id, name, slug, origin_period_id, origin_decade, origin_country, description, musical_characteristics, related_genres, main_composers, representative_works, cultural_influences, image_url, theme_color, is_active, created_at)
VALUES ('00000000-0000-0000-0000-000000000001', 'f37e768f-1d17-4fe8-b7e1-217a2c073607', $$Samba$$, $$samba$$, NULL, $$1910$$, $$Brasil$$, $$Gênero símbolo do Brasil. Nasceu nos terreiros e rodas de samba do Rio de Janeiro. Patrimônio cultural imaterial da humanidade (UNESCO).$$, $${"obras": ["Pelo Telefone (1º samba gravado)", "Aquarela do Brasil", "Mas Que Nada", "O Mundo é um Moinho - Cartola"], "estilos": ["Samba de Roda", "Samba-enredo", "Samba-canção", "Samba de Breque", "Pagode", "Samba-rock", "Samba-jazz"], "artistas": ["Cartola", "Paulinho da Viola", "Clara Nunes", "Beth Carvalho", "Zeca Pagodinho", "Martinho da Vila", "Dona Ivone Lara", "Noel Rosa"], "estrutura": ["Compasso 2/4 sincopado", "Batucada característica", "Harmonia em tonalidade maior", "Partido-alto (improviso)", "Roda de samba (coletivo)"], "instrumentos": ["Surdo", "Pandeiro", "Tamborim", "Cuíca", "Cavaquinho", "Violão de 7 cordas", "Repique", "Agogô"]}$$, '[]', '[]', '[]', $$Rio de Janeiro, início séc. XX. Raízes africanas (batuque, lundu) + cultura afro-brasileira. Carnaval, resistência cultural, identidade nacional.$$, NULL, $$#10b981$$, true, '2025-10-27 18:41:40.135539+00'::timestamptz)
ON CONFLICT (id) DO NOTHING;

